local _M = {}

-- Simple XML parser that handles entity references
-- Compatible with OpenResty environment

local entity_map = {
    ["&lt;"] = "<",
    ["&gt;"] = ">",
    ["&amp;"] = "&",
    ["&quot;"] = '"',
    ["&apos;"] = "'",
}

local function decode_entities(str)
    if not str then return str end
    str = str:gsub("&#x(%x+);", function(hex)
        return string.char(tonumber(hex, 16))
    end)
    str = str:gsub("&#(%d+);", function(dec)
        return string.char(tonumber(dec))
    end)
    for entity, char in pairs(entity_map) do
        str = str:gsub(entity, char)
    end
    return str
end

local function trim(s)
    if not s then return nil end
    return s:match("^%s*(.-)%s*$")
end

local function parse_attributes(attr_str)
    local attrs = {}
    if not attr_str or attr_str == "" then
        return attrs
    end
    for key, value in attr_str:gmatch('([%w_:%-]+)%s*=%s*"([^"]*)"') do
        attrs[key] = decode_entities(value)
    end
    for key, value in attr_str:gmatch("([%w_:%-]+)%s*=%s*'([^']*)'") do
        attrs[key] = decode_entities(value)
    end
    return attrs
end

local function parse_xml(xml_str)
    if not xml_str or xml_str == "" then
        return nil, "empty XML input"
    end

    -- Remove XML declaration
    xml_str = xml_str:gsub("<%?xml[^%?]*%?>", "")
    -- Remove comments
    xml_str = xml_str:gsub("<!%-%-.-%--%>", "")
    -- Remove CDATA sections by extracting content
    xml_str = xml_str:gsub("<!%[CDATA%[(.-)%]%]>", "%1")

    local stack = {}
    local root = { _children = {}, _type = "root" }
    local current = root

    local pos = 1
    while pos <= #xml_str do
        local text_start, tag_start = xml_str:find("<", pos)
        if not tag_start then
            -- Remaining text
            local remaining = trim(xml_str:sub(pos))
            if remaining and remaining ~= "" then
                current._text = (current._text or "") .. decode_entities(remaining)
            end
            break
        end

        -- Capture text before tag
        if tag_start > pos then
            local text = xml_str:sub(pos, tag_start - 1)
            text = trim(text)
            if text and text ~= "" then
                current._text = (current._text or "") .. decode_entities(text)
            end
        end

        -- Self-closing tag
        local self_close_match = xml_str:match("^<([%w_:%-]+)(.-)/>", tag_start)
        if self_close_match then
            local tag_name = self_close_match
            local attr_str = xml_str:match("^<[%w_:%-]+(.-)/>", tag_start)
            local node = {
                _name = tag_name,
                _type = "element",
                _attrs = parse_attributes(attr_str),
                _children = {},
                _text = nil,
            }
            table.insert(current._children, node)
            if not current[tag_name] then
                current[tag_name] = node
            elseif type(current[tag_name]) == "table" and current[tag_name]._type then
                -- Convert single element to array
                current[tag_name] = { current[tag_name], node }
            elseif type(current[tag_name]) == "table" then
                table.insert(current[tag_name], node)
            end
            local _, end_pos = xml_str:find("/>", tag_start)
            pos = end_pos + 1

        -- Closing tag
        elseif xml_str:sub(tag_start, tag_start + 1) == "</" then
            local close_tag = xml_str:match("^</([%w_:%-]+)%s*>", tag_start)
            if not close_tag then
                return nil, "malformed closing tag at position " .. tag_start
            end
            if current._name ~= close_tag then
                return nil, string.format(
                    "mismatched closing tag: expected </%s>, got </%s> at position %d",
                    tostring(current._name), close_tag, tag_start
                )
            end
            current = table.remove(stack)
            if not current then
                return nil, "unexpected closing tag </" .. close_tag .. ">"
            end
            local _, end_pos = xml_str:find(">", tag_start)
            pos = end_pos + 1

        -- Opening tag
        else
            local tag_name = xml_str:match("^<([%w_:%-]+)", tag_start)
            if not tag_name then
                return nil, "malformed opening tag at position " .. tag_start
            end
            local tag_end = xml_str:find(">", tag_start)
            if not tag_end then
                return nil, "unclosed tag at position " .. tag_start
            end
            local full_tag = xml_str:sub(tag_start, tag_end)
            local attr_str = full_tag:match("^<[%w_:%-]+(.-)>$")

            local node = {
                _name = tag_name,
                _type = "element",
                _attrs = parse_attributes(attr_str),
                _children = {},
                _text = nil,
            }
            table.insert(current._children, node)
            if not current[tag_name] then
                current[tag_name] = node
            elseif type(current[tag_name]) == "table" and current[tag_name]._type then
                current[tag_name] = { current[tag_name], node }
            elseif type(current[tag_name]) == "table" then
                table.insert(current[tag_name], node)
            end

            table.insert(stack, current)
            current = node
            pos = tag_end + 1
        end
    end

    if #stack > 0 then
        return nil, "unclosed tags remaining"
    end

    if #root._children == 0 then
        return nil, "no root element found"
    end

    return root._children[1], nil
end

-- Strip namespace prefix from tag name
local function strip_ns(name)
    if not name then return name end
    local stripped = name:match(":(.+)$")
    return stripped or name
end

-- Find element by local name (ignoring namespace prefix), searches recursively
local function find_element(node, local_name, recursive)
    if not node or not node._children then
        return nil
    end
    for _, child in ipairs(node._children) do
        if strip_ns(child._name) == local_name then
            return child
        end
    end
    if recursive then
        for _, child in ipairs(node._children) do
            local found = find_element(child, local_name, true)
            if found then
                return found
            end
        end
    end
    return nil
end

-- Find all elements by local name
local function find_all_elements(node, local_name, recursive, results)
    results = results or {}
    if not node or not node._children then
        return results
    end
    for _, child in ipairs(node._children) do
        if strip_ns(child._name) == local_name then
            table.insert(results, child)
        end
        if recursive then
            find_all_elements(child, local_name, true, results)
        end
    end
    return results
end

-- Get text content of an element (including nested text)
local function get_text(node)
    if not node then return nil end
    if node._text then return node._text end
    if node._children and #node._children > 0 then
        local parts = {}
        for _, child in ipairs(node._children) do
            local t = get_text(child)
            if t then table.insert(parts, t) end
        end
        if #parts > 0 then
            return table.concat(parts)
        end
    end
    return nil
end

-- Extract child element text by local name
local function get_child_text(node, child_name)
    local child = find_element(node, child_name, false)
    return get_text(child)
end

-- Convert element to a simple Lua table
local function element_to_table(node)
    if not node then return nil end

    local result = {}
    local has_children = node._children and #node._children > 0

    if not has_children then
        return node._text
    end

    for _, child in ipairs(node._children) do
        local key = strip_ns(child._name)
        local value = element_to_table(child)
        if result[key] then
            if type(result[key]) ~= "table" or (type(result[key]) == "table" and result[key]._is_array == nil) then
                result[key] = { result[key], _is_array = true }
            end
            table.insert(result[key], value)
        else
            result[key] = value
        end
    end

    return result
end

-- Extract SOAP action from headers
local function get_soap_action(headers)
    -- SOAPAction header (SOAP 1.1)
    local soap_action = headers["SOAPAction"] or headers["soapaction"]
    if soap_action then
        -- Remove surrounding quotes if present
        soap_action = soap_action:gsub('^"', ''):gsub('"$', '')
        return soap_action
    end

    -- Content-Type action parameter (SOAP 1.2)
    local content_type = headers["Content-Type"] or headers["content-type"] or ""
    local action = content_type:match('action="([^"]*)"')
    if action then
        return action
    end

    return nil
end

-- Parse SOAP envelope and extract relevant parts
local function parse_soap_envelope(xml_root)
    if not xml_root then
        return nil, "no XML root element"
    end

    local envelope_name = strip_ns(xml_root._name)
    if envelope_name ~= "Envelope" then
        return nil, "root element is not a SOAP Envelope, got: " .. tostring(xml_root._name)
    end

    local result = {
        envelope = xml_root,
        header = nil,
        body = nil,
        header_elements = {},
        body_elements = {},
        operation = nil,
        operation_element = nil,
        fault = nil,
    }

    -- Find Header and Body
    result.header = find_element(xml_root, "Header", false)
    result.body = find_element(xml_root, "Body", false)

    if not result.body then
        return nil, "SOAP Body not found in Envelope"
    end

    -- Extract header elements
    if result.header and result.header._children then
        for _, child in ipairs(result.header._children) do
            local local_name = strip_ns(child._name)
            result.header_elements[local_name] = child
        end
    end

    -- Extract body elements
    if result.body._children then
        for _, child in ipairs(result.body._children) do
            local local_name = strip_ns(child._name)
            result.body_elements[local_name] = child
        end
    end

    -- Check for SOAP Fault
    result.fault = find_element(result.body, "Fault", false)

    -- Determine operation (first child of Body that isn't a Fault)
    if result.body._children and #result.body._children > 0 then
        for _, child in ipairs(result.body._children) do
            local local_name = strip_ns(child._name)
            if local_name ~= "Fault" then
                result.operation = local_name
                result.operation_element = child
                break
            end
        end
    end

    return result, nil
end

-- Build a SOAP fault response XML
local function build_soap_fault(fault_code, fault_string, detail, soap_version)
    soap_version = soap_version or "1.1"

    if soap_version == "1.2" then
        local xml = '<?xml version="1.0" encoding="UTF-8"?>\n'
        xml = xml .. '<soap:Envelope xmlns:soap="http://www.w3.org/2003/05/soap-envelope">\n'
        xml = xml .. '  <soap:Body>\n'
        xml = xml .. '    <soap:Fault>\n'
        xml = xml .. '      <soap:Code>\n'
        xml = xml .. '        <soap:Value>' .. (fault_code or "soap:Receiver") .. '</soap:Value>\n'
        xml = xml .. '      </soap:Code>\n'
        xml = xml .. '      <soap:Reason>\n'
        xml = xml .. '        <soap:Text xml:lang="en">' .. (fault_string or "Internal Error") .. '</soap:Text>\n'
        xml = xml .. '      </soap:Reason>\n'
        if detail then
            xml = xml .. '      <soap:Detail>' .. detail .. '</soap:Detail>\n'
        end
        xml = xml .. '    </soap:Fault>\n'
        xml = xml .. '  </soap:Body>\n'
        xml = xml .. '</soap:Envelope>'
        return xml
    else
        local xml = '<?xml version="1.0" encoding="UTF-8"?>\n'
        xml = xml .. '<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">\n'
        xml = xml .. '  <soap:Body>\n'
        xml = xml .. '    <soap:Fault>\n'
        xml = xml .. '      <faultcode>' .. (fault_code or "soap:Server") .. '</faultcode>\n'
        xml = xml .. '      <faultstring>' .. (fault_string or "Internal Error") .. '</faultstring>\n'
        if detail then
            xml = xml .. '      <detail>' .. detail .. '</detail>\n'
        end
        xml = xml .. '    </soap:Fault>\n'
        xml = xml .. '  </soap:Body>\n'
        xml = xml .. '</soap:Envelope>'
        return xml
    end
end

-- Detect SOAP version from content type or envelope namespace
local function detect_soap_version(content_type, xml_root)
    if content_type then
        if content_type:find("application/soap%+xml") then
            return "1.2"
        elseif content_type:find("text/xml") then
            return "1.1"
        end
    end

    if xml_root and xml_root._attrs then
        for attr_name, attr_value in pairs(xml_root._attrs) do
            if attr_value == "http://www.w3.org/2003/05/soap-envelope" then
                return "1.2"
            elseif attr_value == "http://schemas.xmlsoap.org/soap/envelope/" then
                return "1.1"
            end
        end
    end

    return "1.1"
end

-- Main request handler for OpenResty
function _M.handle_request()
    -- Read request body
    ngx.req.read_body()
