    if not body then
        -- Body might be in a temp file
        local body_file = ngx.req.get_body_file()
        if body_file then
            local fh, err = io.open(body_file, "r")
            if fh then
                body = fh:read("*a")
                fh:close()
            else
                ngx.log(ngx.ERR, "failed to read body file: ", err)
            end